      'from typing import List\n\n\ndef partition_kth(a: List[int], lo: int, hi: int) -> int:\n    pivot = a[hi]\n    store = lo\n    for i in range(lo, hi):\n        if a[i] <= pivot:\n            a[i], a[store] = a[store], a[i]\n            store += 1\n    a[store], a[hi] = a[hi], a[store]\n    return store\n\n\ndef find_kth_largest(a: List[int], k: int) -> int:\n    target = len(a) - k\n    lo, hi = 0, len(a) - 1\n    while lo < hi:\n        p = partition_kth(a, lo, hi)\n        if p == target:\n            return a[p]\n        if p < target:\n            lo = p + 1\n        else:\n            hi = p - 1\n    return a[lo]',
    java: 'import java.util.*;\n\nclass Solution {\n    static int partitionKth(long[] a, int lo, int hi) {\n        long pivot = a[hi];\n        int store = lo;\n        for (int i = lo; i < hi; i++) {\n            if (a[i] <= pivot) {\n                long t = a[i];\n                a[i] = a[store];\n                a[store] = t;\n                store++;\n            }\n        }\n        long t = a[store];\n        a[store] = a[hi];\n        a[hi] = t;\n        return store;\n    }\n\n    static long findKthLargest(long[] a, int k) {\n        int target = a.length - k;\n        int lo = 0, hi = a.length - 1;\n        while (lo < hi) {\n            int p = partitionKth(a, lo, hi);\n            if (p == target) {\n                return a[p];\n            }\n            if (p < target) {\n                lo = p + 1;\n            } else {\n                hi = p - 1;\n            }\n        }\n        return a[lo];\n    }\n}',
