  'prep-linked-lists-reverse-nodes-in-k-group': {
    python:
      'from typing import Optional\n\n\nclass ListNode:\n    def __init__(self, val: int = 0, next: "Optional[ListNode]" = None):\n        self.val = val\n        self.next = next\n\n\ndef reverseKGroup(head: Optional[ListNode], k: int) -> Optional[ListNode]:\n    dummy = ListNode(next=head)\n    group_prev = dummy\n    while True:\n        kth = group_prev\n        for _ in range(k):\n            kth = kth.next\n            if kth is None:\n                return dummy.next\n        group_next = kth.next\n        prev, cur = group_next, group_prev.next\n        while cur is not group_next:\n            tmp = cur.next\n            cur.next = prev\n            prev = cur\n            cur = tmp\n        tmp = group_prev.next\n        group_prev.next = kth\n        group_prev = tmp',
    java: 'import java.util.*;\n\nclass Solution {\n    static class ListNode {\n        int val;\n        ListNode next;\n        ListNode() {}\n        ListNode(int val) { this.val = val; }\n        ListNode(int val, ListNode next) { this.val = val; this.next = next; }\n    }\n\n    public ListNode reverseKGroup(ListNode head, int k) {\n        ListNode dummy = new ListNode();\n        dummy.next = head;\n        ListNode groupPrev = dummy;\n        while (true) {\n            ListNode kth = groupPrev;\n            for (int i = 0; i < k; i++) {\n                kth = kth.next;\n                if (kth == null) {\n                    return dummy.next;\n                }\n            }\n            ListNode groupNext = kth.next;\n            ListNode prev = groupNext, cur = groupPrev.next;\n            while (cur != groupNext) {\n                ListNode tmp = cur.next;\n                cur.next = prev;\n                prev = cur;\n                cur = tmp;\n            }\n            ListNode tmp = groupPrev.next;\n            groupPrev.next = kth;\n            groupPrev = tmp;\n        }\n    }\n}',
  },
  'prep-linked-lists-sort-linked-list': {
    python:
      'from typing import Optional\n\n\nclass ListNode:\n    def __init__(self, val: int = 0, next: "Optional[ListNode]" = None):\n        self.val = val\n        self.next = next\n\n\ndef sortLinkedList(head: Optional[ListNode]) -> Optional[ListNode]:\n    if head is None or head.next is None:\n        return head\n    slow, fast = head, head.next\n    while fast is not None and fast.next is not None:\n        slow = slow.next\n        fast = fast.next.next\n    mid = slow.next\n    slow.next = None\n    left = sortLinkedList(head)\n    right = sortLinkedList(mid)\n    return mergeSorted(left, right)\n\n\ndef mergeSorted(a: Optional[ListNode], b: Optional[ListNode]) -> Optional[ListNode]:\n    dummy = ListNode()\n    cur = dummy\n    while a is not None and b is not None:\n        if a.val < b.val:\n            cur.next = a\n            a = a.next\n        else:\n            cur.next = b\n            b = b.next\n        cur = cur.next\n    if a is not None:\n        cur.next = a\n    else:\n        cur.next = b\n    return dummy.next',
    java: 'import java.util.*;\n\nclass Solution {\n\n    static class ListNode {\n        long val;\n        ListNode next;\n\n        ListNode() {\n        }\n\n        ListNode(long val) {\n            this.val = val;\n        }\n    }\n\n    ListNode sortLinkedList(ListNode head) {\n        if (head == null || head.next == null) {\n            return head;\n        }\n        ListNode slow = head, fast = head.next;\n        while (fast != null && fast.next != null) {\n            slow = slow.next;\n            fast = fast.next.next;\n        }\n        ListNode mid = slow.next;\n        slow.next = null;\n        ListNode left = sortLinkedList(head);\n        ListNode right = sortLinkedList(mid);\n        return mergeSorted(left, right);\n    }\n\n    ListNode mergeSorted(ListNode a, ListNode b) {\n        ListNode dummy = new ListNode();\n        ListNode cur = dummy;\n        while (a != null && b != null) {\n            if (a.val < b.val) {\n                cur.next = a;\n                a = a.next;\n            } else {\n                cur.next = b;\n                b = b.next;\n            }\n            cur = cur.next;\n        }\n        if (a != null) {\n            cur.next = a;\n        } else {\n            cur.next = b;\n        }\n        return dummy.next;\n    }\n}',
  },
