      'from typing import List\n\n\ndef searchMatrix(matrix: List[List[int]], target: int) -> bool:\n    m, n = len(matrix), len(matrix[0])\n    r, c = 0, n - 1\n    while r < m and c >= 0:\n        if matrix[r][c] == target:\n            return True\n        if matrix[r][c] > target:\n            c -= 1\n        else:\n            r += 1\n    return False',
