  'prep-stacks-queues-basic-calculator': {
    python:
      "def calculate(s: str) -> int:\n    b = s.encode('utf-8')\n    stack = []\n    res, sign = 0, 1\n    i = 0\n    n = len(b)\n    while i < n:\n        c = b[i]\n        if ord('0') <= c <= ord('9'):\n            num = 0\n            while i < n and ord('0') <= b[i] <= ord('9'):\n                num = num * 10 + (b[i] - ord('0'))\n                i += 1\n            i -= 1\n            res += sign * num\n        elif c == ord('+'):\n            sign = 1\n        elif c == ord('-'):\n            sign = -1\n        elif c == ord('('):\n            stack.append(res)\n            stack.append(sign)\n            res, sign = 0, 1\n        elif c == ord(')'):\n            prev_sign = stack.pop()\n            prev_res = stack.pop()\n            res = prev_res + prev_sign * res\n        i += 1\n    return res",
    java: "import java.util.*;\nimport java.nio.charset.StandardCharsets;\n\nclass Solution {\n    public long calculate(String s) {\n        byte[] b = s.getBytes(StandardCharsets.UTF_8);\n        Deque<Long> stack = new ArrayDeque<>();\n        long res = 0, sign = 1;\n        int n = b.length;\n        for (int i = 0; i < n; i++) {\n            int c = b[i] & 0xFF;\n            if (c >= '0' && c <= '9') {\n                long num = 0;\n                while (i < n && (b[i] & 0xFF) >= '0' && (b[i] & 0xFF) <= '9') {\n                    num = num * 10 + ((b[i] & 0xFF) - '0');\n                    i++;\n                }\n                i--;\n                res += sign * num;\n            } else if (c == '+') {\n                sign = 1;\n            } else if (c == '-') {\n                sign = -1;\n            } else if (c == '(') {\n                stack.push(res);\n                stack.push(sign);\n                res = 0;\n                sign = 1;\n            } else if (c == ')') {\n                long prevSign = stack.pop();\n                long prevRes = stack.pop();\n                res = prevRes + prevSign * res;\n            }\n        }\n        return res;\n    }\n}",
  },
