    python:
      'from typing import Optional\n\n\nclass ListNode:\n    def __init__(self, val=0, next=None):\n        self.val = val\n        self.next = next\n\n\nclass TreeNode:\n    def __init__(self, val=0, left=None, right=None):\n        self.val = val\n        self.left = left\n        self.right = right\n\n\ndef convert_sorted_linked_list_to_bst(head: Optional[ListNode]) -> Optional[TreeNode]:\n    n = 0\n    cur = head\n    while cur is not None:\n        n += 1\n        cur = cur.next\n\n    state = {"cur": head}\n\n    def build(l: int, r: int) -> Optional[TreeNode]:\n        if l > r:\n            return None\n        m = (l + r) // 2\n        left = build(l, m - 1)\n        node = TreeNode(state["cur"].val)\n        state["cur"] = state["cur"].next\n        node.left = left\n        node.right = build(m + 1, r)\n        return node\n\n    return build(0, n - 1)',
    java: 'import java.util.*;\n\nclass Solution {\n\n    public static class ListNode {\n        long val;\n        ListNode next;\n        ListNode(long val) { this.val = val; }\n        ListNode(long val, ListNode next) { this.val = val; this.next = next; }\n    }\n\n    public static class TreeNode {\n        long val;\n        TreeNode left, right;\n        TreeNode(long val) { this.val = val; }\n    }\n\n    private ListNode cur;\n\n    public TreeNode convertSortedLinkedListToBst(ListNode head) {\n        int n = 0;\n        for (ListNode c = head; c != null; c = c.next) {\n            n++;\n        }\n        cur = head;\n        return build(0, n - 1);\n    }\n\n    private TreeNode build(int l, int r) {\n        if (l > r) {\n            return null;\n        }\n        int m = (l + r) / 2;\n        TreeNode left = build(l, m - 1);\n        TreeNode node = new TreeNode(cur.val);\n        cur = cur.next;\n        node.left = left;\n        node.right = build(m + 1, r);\n        return node;\n    }\n}',
