  'prep-trees-nary-tree-distance-of-two-nodes': {
    python:
      'from typing import List, Optional\n\n\nclass NaryNode:\n    def __init__(self, val: int, children: Optional[List["NaryNode"]] = None):\n        self.val = val\n        self.children = children if children is not None else []\n\n\ndef find_lowest_common_ancestor(\n    root: Optional[NaryNode], a: Optional[NaryNode], b: Optional[NaryNode]\n) -> Optional[NaryNode]:\n    if root is None:\n        return None\n    if root is a or root is b:\n        return root\n    found = None\n    count = 0\n    for child in root.children:\n        lca = find_lowest_common_ancestor(child, a, b)\n        if lca is not None:\n            count += 1\n            found = lca\n    if count >= 2:\n        return root\n    return found\n\n\ndef level_distance(root: Optional[NaryNode], target: Optional[NaryNode]) -> int:\n    if root is target:\n        return 0\n    level = 0\n    frontier = list(root.children) if root is not None else []\n    while len(frontier) > 0:\n        level += 1\n        nxt: List[NaryNode] = []\n        for node in frontier:\n            if node is target:\n                return level\n            nxt.extend(node.children)\n        frontier = nxt\n    return -1\n\n\ndef find_distance_of_two_nodes(\n    root: Optional[NaryNode], a: Optional[NaryNode], b: Optional[NaryNode]\n) -> int:\n    lca = find_lowest_common_ancestor(root, a, b)\n    return level_distance(lca, a) + level_distance(lca, b)',
    java: 'import java.util.*;\n\nclass Solution {\n\n    static class NaryNode {\n        long val;\n        List<NaryNode> children;\n\n        NaryNode(long val, List<NaryNode> children) {\n            this.val = val;\n            this.children = children;\n        }\n    }\n\n    NaryNode findLowestCommonAncestor(NaryNode root, NaryNode a, NaryNode b) {\n        if (root == null) {\n            return null;\n        }\n        if (root == a || root == b) {\n            return root;\n        }\n        NaryNode found = null;\n        int count = 0;\n        for (NaryNode child : root.children) {\n            NaryNode lca = findLowestCommonAncestor(child, a, b);\n            if (lca != null) {\n                count++;\n                found = lca;\n            }\n        }\n        if (count >= 2) {\n            return root;\n        }\n        return found;\n    }\n\n    int levelDistance(NaryNode root, NaryNode target) {\n        if (root == target) {\n            return 0;\n        }\n        int level = 0;\n        List<NaryNode> frontier = (root != null) ? root.children : new ArrayList<>();\n        while (frontier.size() > 0) {\n            level++;\n            List<NaryNode> next = new ArrayList<>();\n            for (NaryNode node : frontier) {\n                if (node == target) {\n                    return level;\n                }\n                next.addAll(node.children);\n            }\n            frontier = next;\n        }\n        return -1;\n    }\n\n    int findDistanceOfTwoNodes(NaryNode root, NaryNode a, NaryNode b) {\n        NaryNode lca = findLowestCommonAncestor(root, a, b);\n        return levelDistance(lca, a) + levelDistance(lca, b);\n    }\n}',
  },
  'prep-trees-find-kth-largest-in-bst': {
    python:
      'from typing import Optional\n\n\nclass TreeNode:\n    def __init__(self, val: int = 0, left: "Optional[TreeNode]" = None, right: "Optional[TreeNode]" = None):\n        self.val = val\n        self.left = left\n        self.right = right\n\n\ndef find_kth_largest_in_bst(root: Optional[TreeNode], k: int) -> int:\n    ans = 0\n    state = {"k": k}\n\n    def dfs(node: Optional[TreeNode]) -> None:\n        if node is None or state["k"] == 0:\n            return\n        dfs(node.right)\n        state["k"] -= 1\n        if state["k"] == 0:\n            nonlocal ans\n            ans = node.val\n            return\n        dfs(node.left)\n\n    dfs(root)\n    return ans',
    java: 'import java.util.*;\n\nclass Solution {\n\n    public static class TreeNode {\n        long val;\n        TreeNode left, right;\n        TreeNode() {}\n        TreeNode(long val) { this.val = val; }\n        TreeNode(long val, TreeNode left, TreeNode right) {\n            this.val = val;\n            this.left = left;\n            this.right = right;\n        }\n    }\n\n    private long k;\n    private long ans;\n\n    public long findKthLargestInBst(TreeNode root, long k) {\n        this.ans = 0;\n        this.k = k;\n        dfs(root);\n        return ans;\n    }\n\n    private void dfs(TreeNode node) {\n        if (node == null || k == 0) {\n            return;\n        }\n        dfs(node.right);\n        k--;\n        if (k == 0) {\n            ans = node.val;\n            return;\n        }\n        dfs(node.left);\n    }\n}',
  },
  'prep-trees-find-leaves-of-binary-tree': {
    python:
      "from typing import List, Optional\n\n\nclass TreeNode:\n    def __init__(self, val: int = 0, left: 'Optional[TreeNode]' = None, right: 'Optional[TreeNode]' = None):\n        self.val = val\n        self.left = left\n        self.right = right\n\n\nclass Solution:\n    def findLeaves(self, root: Optional[TreeNode]) -> List[List[int]]:\n        res: List[List[int]] = []\n\n        def dfs(node: Optional[TreeNode]) -> int:\n            if node is None:\n                return -1\n            h = dfs(node.left)\n            r = dfs(node.right)\n            if r > h:\n                h = r\n            h += 1\n            if h == len(res):\n                res.append([])\n            res[h].append(node.val)\n            return h\n\n        dfs(root)\n        return res",
    java: 'import java.util.*;\n\nclass Solution {\n\n    public static class TreeNode {\n        long val;\n        TreeNode left;\n        TreeNode right;\n        TreeNode() {}\n        TreeNode(long val) { this.val = val; }\n        TreeNode(long val, TreeNode left, TreeNode right) {\n            this.val = val;\n            this.left = left;\n            this.right = right;\n        }\n    }\n\n    public List<List<Long>> findLeaves(TreeNode root) {\n        List<List<Long>> res = new ArrayList<>();\n        dfs(root, res);\n        return res;\n    }\n\n    private int dfs(TreeNode node, List<List<Long>> res) {\n        if (node == null) {\n            return -1;\n        }\n        int h = dfs(node.left, res);\n        int r = dfs(node.right, res);\n        if (r > h) {\n            h = r;\n        }\n        h++;\n        if (h == res.size()) {\n            res.add(new ArrayList<>());\n        }\n        res.get(h).add(node.val);\n        return h;\n    }\n}',
  },
