  'prep-trees-flip-tree': {
    python:
      'from typing import Optional\n\n\nclass TreeNode:\n    def __init__(self, val=0, left=None, right=None):\n        self.val = val\n        self.left = left\n        self.right = right\n\n\ndef flipTree(root: Optional[TreeNode]) -> Optional[TreeNode]:\n    if root is None:\n        return None\n    root.left, root.right = flipTree(root.right), flipTree(root.left)\n    return root\n',
    java: 'import java.util.*;\n\nclass Solution {\n\n    static class TreeNode {\n        long val;\n        TreeNode left, right;\n        TreeNode(long val) { this.val = val; }\n    }\n\n    static TreeNode flipTree(TreeNode root) {\n        if (root == null) {\n            return null;\n        }\n        TreeNode newLeft = flipTree(root.right);\n        TreeNode newRight = flipTree(root.left);\n        root.left = newLeft;\n        root.right = newRight;\n        return root;\n    }\n}\n',
  },
  'prep-trees-get-diameter': {
    python:
      'from typing import Optional\n\n\nclass TreeNode:\n    def __init__(self, val: int = 0, left: "Optional[TreeNode]" = None, right: "Optional[TreeNode]" = None):\n        self.val = val\n        self.left = left\n        self.right = right\n\n\ndef get_diameter(root: Optional[TreeNode]) -> int:\n    best = 0\n\n    def height(node: Optional[TreeNode]) -> int:\n        nonlocal best\n        if node is None:\n            return 0\n        l = height(node.left)\n        r = height(node.right)\n        if l + r > best:\n            best = l + r\n        if l > r:\n            return l + 1\n        return r + 1\n\n    height(root)\n    return best',
    java: 'import java.util.*;\n\nclass Solution {\n\n    public static class TreeNode {\n        int val;\n        TreeNode left, right;\n        TreeNode() {}\n        TreeNode(int val) { this.val = val; }\n        TreeNode(int val, TreeNode left, TreeNode right) {\n            this.val = val;\n            this.left = left;\n            this.right = right;\n        }\n    }\n\n    public int getDiameter(TreeNode root) {\n        int[] best = new int[]{0};\n        height(root, best);\n        return best[0];\n    }\n\n    private int height(TreeNode node, int[] best) {\n        if (node == null) return 0;\n        int l = height(node.left, best);\n        int r = height(node.right, best);\n        if (l + r > best[0]) best[0] = l + r;\n        if (l > r) return l + 1;\n        return r + 1;\n    }\n}',
  },
  'prep-trees-nary-tree-diameter': {
    python:
      'from typing import List, Optional\n\n\nclass NaryNode:\n    def __init__(self, val: int, children: Optional[List["NaryNode"]] = None):\n        self.val = val\n        self.children = children if children is not None else []\n\n\ndef get_height(root: Optional[NaryNode]) -> int:\n    if root is None:\n        return -1\n    max_child = -1\n    for child in root.children:\n        h = get_height(child)\n        if h > max_child:\n            max_child = h\n    return max_child + 1\n\n\ndef get_diameter(root: Optional[NaryNode]) -> int:\n    if root is None:\n        return 0\n    max1, max2 = -1, -1\n    for child in root.children:\n        h = get_height(child)\n        if h > max1:\n            max2 = max1\n            max1 = h\n        elif h > max2:\n            max2 = h\n    diameter = 0\n    if max1 >= 0 and max2 >= 0:\n        diameter = max1 + max2 + 2\n    elif max1 >= 0:\n        diameter = max1 + 1\n    for child in root.children:\n        d = get_diameter(child)\n        if d > diameter:\n            diameter = d\n    return diameter',
    java: 'import java.util.*;\n\nclass Solution {\n\n    static class NaryNode {\n        int val;\n        List<NaryNode> children;\n\n        NaryNode(int val, List<NaryNode> children) {\n            this.val = val;\n            this.children = children;\n        }\n    }\n\n    int getHeight(NaryNode root) {\n        if (root == null) {\n            return -1;\n        }\n        int maxChild = -1;\n        for (NaryNode child : root.children) {\n            int h = getHeight(child);\n            if (h > maxChild) {\n                maxChild = h;\n            }\n        }\n        return maxChild + 1;\n    }\n\n    int getDiameter(NaryNode root) {\n        if (root == null) {\n            return 0;\n        }\n        int max1 = -1, max2 = -1;\n        for (NaryNode child : root.children) {\n            int h = getHeight(child);\n            if (h > max1) {\n                max2 = max1;\n                max1 = h;\n            } else if (h > max2) {\n                max2 = h;\n            }\n        }\n        int diameter = 0;\n        if (max1 >= 0 && max2 >= 0) {\n            diameter = max1 + max2 + 2;\n        } else if (max1 >= 0) {\n            diameter = max1 + 1;\n        }\n        for (NaryNode child : root.children) {\n            int d = getDiameter(child);\n            if (d > diameter) {\n                diameter = d;\n            }\n        }\n        return diameter;\n    }\n}',
  },
