      "from typing import List, Optional\n\n\nclass TreeNode:\n    def __init__(self, val: int = 0, left: 'Optional[TreeNode]' = None, right: 'Optional[TreeNode]' = None):\n        self.val = val\n        self.left = left\n        self.right = right\n\n\ndef levelOrder(root: Optional[TreeNode]) -> Optional[List[List[int]]]:\n    if root is None:\n        return None\n    out: List[List[int]] = []\n    q: List[TreeNode] = [root]\n    while len(q) > 0:\n        sz = len(q)\n        level = [0] * sz\n        for i in range(sz):\n            node = q[0]\n            q = q[1:]\n            level[i] = node.val\n            if node.left is not None:\n                q.append(node.left)\n            if node.right is not None:\n                q.append(node.right)\n        out.append(level)\n    return out\n",
    java: 'import java.util.*;\n\nclass Solution {\n\n    public static class TreeNode {\n        long val;\n        TreeNode left, right;\n        TreeNode() {}\n        TreeNode(long val) { this.val = val; }\n        TreeNode(long val, TreeNode left, TreeNode right) {\n            this.val = val;\n            this.left = left;\n            this.right = right;\n        }\n    }\n\n    public List<List<Long>> levelOrder(TreeNode root) {\n        if (root == null) {\n            return null;\n        }\n        List<List<Long>> out = new ArrayList<>();\n        Deque<TreeNode> q = new ArrayDeque<>();\n        q.addLast(root);\n        while (q.size() > 0) {\n            int sz = q.size();\n            List<Long> level = new ArrayList<>(Collections.nCopies(sz, 0L));\n            for (int i = 0; i < sz; i++) {\n                TreeNode node = q.pollFirst();\n                level.set(i, node.val);\n                if (node.left != null) {\n                    q.addLast(node.left);\n                }\n                if (node.right != null) {\n                    q.addLast(node.right);\n                }\n            }\n            out.add(level);\n        }\n        return out;\n    }\n}\n',
