    java: 'import java.util.*;\n\nclass Solution {\n    public long powerXOfY(long base, long exp) {\n        if (exp < 0) {\n            return 0;\n        }\n        long result = 1;\n        while (exp > 0) {\n            if ((exp & 1) == 1) {\n                result *= base;\n            }\n            base *= base;\n            exp >>= 1;\n        }\n        return result;\n    }\n}',
