      'from typing import List\n\n\ndef arrayManipulation(n: int, queries: List[List[int]]) -> int:\n    diff = [0] * (n + 2)\n    for q in queries:\n        a, b, k = q[0], q[1], q[2]\n        diff[a] += k\n        diff[b + 1] -= k\n    res = 0\n    cur = 0\n    for i in range(1, n + 1):\n        cur += diff[i]\n        if cur > res:\n            res = cur\n    return res',
