      "def min_window(s: str, t: str) -> str:\n    sb = s.encode('utf-8')\n    tb = t.encode('utf-8')\n    if len(sb) < len(tb):\n        return \"\"\n    freq = [0] * 128\n    for i in range(len(tb)):\n        freq[tb[i]] += 1\n    need = len(tb)\n    min_len, min_start = len(sb) + 1, 0\n    l = 0\n    for r in range(len(sb)):\n        if freq[sb[r]] > 0:\n            need -= 1\n        freq[sb[r]] -= 1\n        while need == 0:\n            if r - l + 1 < min_len:\n                min_len = r - l + 1\n                min_start = l\n            freq[sb[l]] += 1\n            if freq[sb[l]] > 0:\n                need += 1\n            l += 1\n    if min_len > len(sb):\n        return \"\"\n    return sb[min_start:min_start + min_len].decode('utf-8')",
    java: 'import java.nio.charset.StandardCharsets;\nimport java.util.*;\n\nclass Solution {\n    public String minWindow(String s, String t) {\n        byte[] sb = s.getBytes(StandardCharsets.UTF_8);\n        byte[] tb = t.getBytes(StandardCharsets.UTF_8);\n        if (sb.length < tb.length) {\n            return "";\n        }\n        int[] freq = new int[128];\n        for (int i = 0; i < tb.length; i++) {\n            freq[tb[i] & 0xFF]++;\n        }\n        int need = tb.length;\n        int minLen = sb.length + 1, minStart = 0;\n        int l = 0;\n        for (int r = 0; r < sb.length; r++) {\n            if (freq[sb[r] & 0xFF] > 0) {\n                need--;\n            }\n            freq[sb[r] & 0xFF]--;\n            while (need == 0) {\n                if (r - l + 1 < minLen) {\n                    minLen = r - l + 1;\n                    minStart = l;\n                }\n                freq[sb[l] & 0xFF]++;\n                if (freq[sb[l] & 0xFF] > 0) {\n                    need++;\n                }\n                l++;\n            }\n        }\n        if (minLen > sb.length) {\n            return "";\n        }\n        return new String(sb, minStart, minLen, StandardCharsets.UTF_8);\n    }\n}',
