    java: 'import java.util.*;\n\nclass Solution {\n    public int maxChunksToSorted(long[] arr) {\n        Deque<Long> stack = new ArrayDeque<>();\n        for (long val : arr) {\n            long mx = val;\n            while (!stack.isEmpty() && stack.peekLast() > val) {\n                long top = stack.pollLast();\n                if (top > mx) {\n                    mx = top;\n                }\n            }\n            stack.addLast(mx);\n        }\n        return stack.size();\n    }\n}',
